mapper.select:

where del_flag = '0'

    and (name like concat('%', #{keyword}, '%') or sku_code like concat('%', #{keyword}, '%'))


    and category_id = #{categoryId}


    and json_contains(regions, json_quote(#{regionId}))


    and status = #{status}

order by sort_order desc, create_time desc, id desc

mapper.insert:
