    #{designerDiscount}, #{regions}, #{spaceTags}, #{sceneTags}, #{specParams}, #{description},
    #{status}, #{sortOrder}, #{delFlag}, #{createBy}, #{createTime}, #{updateBy}, #{updateTime}
