mapper.update:
update bh_product
name = #{name}, sku_code = #{skuCode}, brand = #{brand}, model = #{model}, category_id = #{categoryId}, guide_price = #{guidePrice}, price_unit = #{priceUnit}, designer_discount = #{designerDiscount}, regions = #{regions}, space_tags = #{spaceTags}, scene_tags = #{sceneTags}, spec_params = #{specParams}, description = #{description}, status = #{status}, sort_order = #{sortOrder}, update_by = #{updateBy}, update_time = #{updateTime}
